import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

ABBREV_TO_NAME = {
    'anm': 'Animation', 'anim': 'Animation', 'ani': 'Animation',
    'cfx': 'CharFX',
    'cmp': 'Compositing', 'comp': 'Compositing',
    'fx': 'FX',
    'lay': 'Layout',
    'lgt': 'Lighting', 'light': 'Lighting', 'lit': 'Lighting',
    'mod': 'Modeling', 'model': 'Modeling',
    'rig': 'Rigging',
    'tex': 'Texturing', 'texture': 'Texturing',
    'rnd': 'Rendering', 'render': 'Rendering',
    'mm': 'Matchmove', 'mmv': 'Matchmove',
    'rot': 'Roto', 'roto': 'Roto',
    'pnt': 'Paint', 'paint': 'Paint',
    'dev': 'Development',
}

class PrismGetDepartmentsNode(BaseNode):
    name = "Prism: Get Departments"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_output("departments", "list")
        self.add_output("abbreviations", "list")
        self.add_output("count", "int")

    def _folder_to_dept_name(self, folder):
        return ABBREV_TO_NAME.get(folder.lower(), folder.title())

    def _depts_from_prism_api(self, core, entity):
        for method in ('getSteps', 'getPipelineSteps'):
            fn = getattr(core.entities, method, None)
            if not callable(fn):
                continue
            try:
                result = fn(entity) or []
                if result and isinstance(result[0], dict):
                    return [d.get('name', d.get('abbreviation', '')) for d in result if d]
                return [str(d) for d in result]
            except Exception:
                pass
        return []

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        if core is None:
            self.log_error('No PrismCore found.')
            return {'departments': [], 'abbreviations': [], 'count': 0}
        shot_path = entity.get('path', '')
        if not shot_path:
            self.log_error('Entity has no path — connect output from prism_get_shot_by_sequence.')
            return {'departments': [], 'abbreviations': [], 'count': 0}
        scenes_root = None
        for candidate in ('Scenefiles', 'Scenes', 'scenes', 'scenefiles'):
            p = os.path.join(shot_path, candidate)
            if os.path.isdir(p):
                scenes_root = p
                break
        if not scenes_root:
            self.log_error(f'No Scenefiles folder in {shot_path}')
            return {'departments': [], 'abbreviations': [], 'count': 0}
        abbrevs = sorted(e.name for e in os.scandir(scenes_root) if e.is_dir())
        names = [self._folder_to_dept_name(a) for a in abbrevs]
        self.log_info(f'departments: {list(zip(abbrevs, names))}')
        return {'departments': names, 'abbreviations': abbrevs, 'count': len(names)}

def register_node():
    return PrismGetDepartmentsNode
